arguments.sparql_query:
PREFIX mw:   <https://purl.org/metalwheel#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?baseMetal ?baseMetalLabel ?proc ?procLabel ?eff ?effLabel WHERE {
  futuram:Copper rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi), "CHEBI"))
  ?chebi mw:hasRecoveryInformation ?ri .
  ?ri mw:hasBaseMetal ?baseMetal ;
      mw:hasRecoveryProcess ?proc ;
      mw:hasExpectedRecoveryEffectiveness ?eff .
  FILTER(?eff IN (mw:TargetedElement, mw:MainlyRecoveredElement))
  OPTIONAL { ?baseMetal rdfs:label ?baseMetalLabel }
  OPTIONAL { ?proc rdfs:label ?procLabel }
  OPTIONAL { ?eff rdfs:label ?effLabel }
}

