arguments.sparql_query:
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?partClass ?partLabel ?wholeClass ?wholeLabel ?proc ?procLabel WHERE {
  # Copper-containing components
  ?part a ?partClass .
  VALUES ?partClass { futuram:Copper futuram:CuAndCuAlloys futuram:pureCu futuram:pureCu_in_elvElectricMotor futuram:pureCu_in_elvEmbeddedElectronicsCables }
  OPTIONAL { ?partClass rdfs:label ?partLabel }
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part ;
      futuram:hasProduction ?proc .
  ?whole futuram:hasCompositionStatement ?stmt ; a ?wholeClass .
  OPTIONAL { ?wholeClass rdfs:label ?wholeLabel }
  OPTIONAL { ?proc rdfs:label ?procLabel }
} ORDER BY ?wholeLabel ?partLabel

