PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX metalwheel: <https://purl.org/metalwheel#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( STRSTARTS(STR(?cls), "https://purl.org/metalwheel#")
       || CONTAINS(LCASE(STR(?label)), "recover")
       || CONTAINS(LCASE(STR(?comment)), "recover")
       || CONTAINS(LCASE(STR(?label)), "metalwheel")
       || CONTAINS(LCASE(STR(?comment)), "metalwheel") )
} LIMIT 50

